// ─── Validate incoming payload ────────────────────────────────────────────
const p = $input.first().json.body || $input.first().json;

if (!p.event_id)           throw new Error('Missing event_id in payload');
if (!p.brand_template_id)  throw new Error('Missing brand_template_id in payload');
if (!p.callback_url)       throw new Error('Missing callback_url in payload');

// ─── Build the /api/canva/generate-poster request body ────────────────────
// Two modes:
//   1. HOD form (via Django proxy): fields already prepared in p.form_fields / p.fields
//   2. Event-save trigger (fire_n8n_branding): flat payload with individual keys
let fields = {};
if (p.form_fields && typeof p.form_fields === 'object' && Object.keys(p.form_fields).length > 0) {
  fields = p.form_fields;
} else if (p.fields && typeof p.fields === 'object' && Object.keys(p.fields).length > 0) {
  fields = p.fields;
} else {
  // Mode 2: extract from flat event payload (used by n8n_poster_service.py)
  const textKeys = [
    'event_name','organizer_department','start_month','start_day','end_day','year',
    'event_time','venue_location',
    'chief_guest_name','chief_guest_position','chief_guest_company','chief_guest_location',
    'committee_member_1_name','committee_member_1_role',
    'committee_member_2_name','committee_member_2_role',
    'committee_member_3_name','committee_member_3_role',
    'committee_member_4_name','committee_member_4_role',
    'committee_member_5_name','committee_member_5_role',
    'committee_member_6_name','committee_member_6_role',
    'website_text','instagram_handle',
  ];
  for (const k of textKeys) {
    if (p[k] && String(p[k]).trim()) fields[k] = String(p[k]).trim();
  }
  // Image fields — pass URL key so Django maps them correctly
  if (p.chief_guest_photo_url) fields['chief_guest_photo'] = p.chief_guest_photo_url;
  if (p.qr_code_image_url)     fields['qr_code_image']     = p.qr_code_image_url;
}

// Resolve backend URL: prefer env var injected at n8n level, fallback to payload
const backendBase = $env.IDCS_BACKEND_URL || p.idcs_backend_url || 'http://localhost:8000';

return [{
  json: {
    event_id:          p.event_id,
    callback_url:      p.callback_url,
    secret:            p.secret || '',
    generate_url:      `${backendBase}/api/canva/generate-poster`,
    brand_template_id: p.brand_template_id,
    export_format:     (p.export_format || p.format || 'png').toLowerCase(),
    fields,
  }
}];

// Pull context from the Build step (not from the HTTP response node)
const ctx  = $('Build Django Request').first().json;
const resp = $input.first().json;

// Django returns { design_id, dataUrl, export_url } on success
// or { detail: '...' } on error
const designId   = resp.design_id  || '';
const exportUrl  = resp.export_url || '';
const warning    = resp.warning    || '';
const errDetail  = resp.detail     || '';

if (errDetail && !designId) {
  // Django returned an explicit error — forward as failure
  return [{ json: { ...ctx, success: false, error: errDetail } }];
}

if (!designId && !exportUrl) {
  return [{ json: { ...ctx, success: false, error: warning || 'No poster generated by Django' } }];
}

const previewLink = designId ? `https://www.canva.com/design/${designId}/view` : '';

return [{ json: {
  ...ctx,
  success:      true,
  design_id:    designId,
  poster_url:   exportUrl,
  preview_link: previewLink,
  data_url:     resp.dataUrl || '',
} }];
